query.value:
SELECT DISTINCT ?name ?mRID ?BaseVoltage_nominalVoltage WHERE {
 ?sys c:IdentifiedObject.mRID ?EquipmentContainer_mRID.
 ?s c:ConnectivityNode.ConnectivityNodeContainer ?sys.
 ?s r:type c:ConnectivityNode.
 ?s c:IdentifiedObject.name ?name.
 ?s c:IdentifiedObject.mRID ?mRID.
 { 
   ?ce c:Equipment.EquipmentContainer ?sys.
   ?ce e:ConductingEquipment.FromConnectivityNode ?s.
   ?ce c:ConductingEquipment.BaseVoltage ?bv.
 } UNION { 
   ?ce c:Equipment.EquipmentContainer ?sys.
   ?ce e:ConductingEquipment.ToConnectivityNode ?s.
   ?ce c:ConductingEquipment.BaseVoltage ?bv.
 } UNION {
   ?pxf c:Equipment.EquipmentContainer ?sys.
   ?end c:PowerTransformerEnd.PowerTransformer ?pxf.
   ?end e:TransformerEnd.ConnectivityNode ?s.
   ?end c:TransformerEnd.BaseVoltage ?bv.
 }
 ?bv c:BaseVoltage.nominalVoltage ?BaseVoltage_nominalVoltage.
}
ORDER by ?name

SELECT ?name ?mRID WHERE {
 ?s r:type c:EquipmentContainer.
 ?s c:IdentifiedObject.name ?name.
 ?s c:IdentifiedObject.mRID ?mRID.
}
ORDER by ?name

SELECT DISTINCT ?nominalVoltage WHERE {
 ?sys c:IdentifiedObject.mRID ?EquipmentContainer_mRID.
 ?s c:Equipment.EquipmentContainer ?sys.
 {?s c:ConductingEquipment.BaseVoltage ?lev.}
  UNION
 { ?end c:PowerTransformerEnd.PowerTransformer ?s.
   ?end c:TransformerEnd.BaseVoltage ?lev.}
 ?lev r:type c:BaseVoltage.
 ?lev c:BaseVoltage.nominalVoltage ?vstr.
  bind(xsd:string(?vstr) as ?xsdstr)
  bind(xsd:float(?xsdstr) as ?nominalVoltage)
}
ORDER BY ?nominalVoltage

SELECT DISTINCT ?mRID ?v ?angle WHERE {
 ?sv e:SvVoltage.ConnectivityNode ?cn.
  bind(substr(str(?cn),strlen(str(?cn))-35) as ?mRID)
 ?sv c:SvVoltage.v ?v.
 ?sv c:SvVoltage.angle ?angle
} ORDER BY ?mRID

SELECT DISTINCT ?mRID ?p ?q WHERE {
 ?sv e:SvPowerFlow.ConductingEquipment ?eq.
  bind(substr(str(?eq),strlen(str(?eq))-35) as ?mRID)
 ?sv c:SvPowerFlow.p ?p.
 ?sv c:SvPowerFlow.q ?q
} ORDER BY ?mRID

SELECT DISTINCT ?mRID ?p ?q WHERE {
 ?sv e:SvPowerFlow.TransformerEnd ?end.
  bind(substr(str(?end),strlen(str(?end))-35) as ?mRID)
 ?sv c:SvPowerFlow.p ?p.
 ?sv c:SvPowerFlow.q ?q
} ORDER BY ?mRID

SELECT DISTINCT ?mRID ?name ?Equipment_mRID ?Equipment_type WHERE {
VALUES ?EquipmentContainer_mRID {"6477751A-0472-4FD6-B3C3-3AD4945CBE56"^^c:String}
# VALUES ?EquipmentContainer_mRID {"62CB0930-211D-4762-B5C1-27BF73EAC7C4"^^c:String}
 ?sys c:IdentifiedObject.mRID ?EquipmentContainer_mRID.
 ?p r:type e:IBRPlant.
 ?p c:IdentifiedObject.name ?name.
 ?p c:IdentifiedObject.mRID ?mRID.
 ?p e:GeneratingPlant.Equipments ?eq.
 ?eq c:Equipment.EquipmentContainer ?sys.
 ?eq c:IdentifiedObject.mRID ?Equipment_mRID.
 {?eq a ?rawtype.
  bind(strafter(str(?rawtype),"#") as ?Equipment_type)}
} ORDER by ?mRID ?Equipment_type ?Equipment_mRID

SELECT DISTINCT ?mRID ?name ?Equipment_mRID ?Equipment_type WHERE {
 ?p r:type e:RotatingMachinePlant.
 ?p c:IdentifiedObject.name ?name.
 ?p c:IdentifiedObject.mRID ?mRID.
 ?p e:GeneratingPlant.Equipments ?eq.
 ?eq c:IdentifiedObject.mRID ?Equipment_mRID.
 {?eq a ?rawtype.
  bind(strafter(str(?rawtype),"#") as ?Equipment_type)}
} ORDER by ?mRID ?Equipment_type ?Equipment_mRID

SELECT DISTINCT ?mRID ?sequenceNumber ?name ?width ?kind ?unit ?multiplier ?phase WHERE {
 ?sys c:IdentifiedObject.mRID ?EquipmentContainer_mRID.
 ?eq r:type c:PowerElectronicsConnection.
 ?eq c:Equipment.EquipmentContainer ?sys.
 ?d e:IEEECigreDLL.PowerElectronicsConnection ?eq.
 ?d c:IdentifiedObject.mRID ?mRID.
 ?p e:IEEECigreDLLInput.IEEECigreDLL ?d.
 ?p e:IEEECigreDLLSignal.sequenceNumber ?sequenceNumber.
 ?p e:IEEECigreDLLSignal.name ?name.
 ?p e:IEEECigreDLLSignal.width ?width.
 {?p e:IEEECigreDLLSignal.unit ?rawunit.
  bind(strafter(str(?rawunit),"UnitSymbol.") as ?unit)}
 {?p e:IEEECigreDLLSignal.multiplier ?rawmult.
  bind(strafter(str(?rawmult),"UnitMultiplier.") as ?multiplier)}
 OPTIONAL {?p e:IEEECigreDLLSignal.phase ?rawphase.
  bind(strafter(str(?rawphase),"Kind.") as ?phase)}
 {?p e:IEEECigreDLLSignal.parameterKind ?rawkind.
  bind(strafter(str(?rawkind),"Kind.") as ?parameterKind)}
 {?p e:IEEECigreDLLInput.kind ?rawsig.
  bind(strafter(str(?rawsig),"Kind.") as ?kind)}
} ORDER by ?mRID ?sequenceNumber

SELECT DISTINCT ?mRID ?sequenceNumber ?name ?width ?kind ?unit ?multiplier ?phase WHERE {
 ?sys c:IdentifiedObject.mRID ?EquipmentContainer_mRID.
 ?eq r:type c:PowerElectronicsConnection.
 ?eq c:Equipment.EquipmentContainer ?sys.
 ?d e:IEEECigreDLL.PowerElectronicsConnection ?eq.
 ?d c:IdentifiedObject.mRID ?mRID.
 ?p e:IEEECigreDLLOutput.IEEECigreDLL ?d.
 ?p e:IEEECigreDLLSignal.sequenceNumber ?sequenceNumber.
 ?p e:IEEECigreDLLSignal.name ?name.
 ?p e:IEEECigreDLLSignal.width ?width.
 {?p e:IEEECigreDLLSignal.unit ?rawunit.
  bind(strafter(str(?rawunit),"UnitSymbol.") as ?unit)}
 {?p e:IEEECigreDLLSignal.multiplier ?rawmult.
  bind(strafter(str(?rawmult),"UnitMultiplier.") as ?multiplier)}
 OPTIONAL {?p e:IEEECigreDLLSignal.phase ?rawphase.
  bind(strafter(str(?rawphase),"Kind.") as ?phase)}
 {?p e:IEEECigreDLLSignal.parameterKind ?rawkind.
  bind(strafter(str(?rawkind),"Kind.") as ?parameterKind)}
 {?p e:IEEECigreDLLOutput.kind ?rawsig.
  bind(strafter(str(?rawsig),"Kind.") as ?kind)}
} ORDER by ?mRID ?sequenceNumber
